#include <stdio.h>

int numProvinces(int** adj, int adjSize, int* adjColSize) {
    int V = adjSize;
    int visited[V];
    for (int i = 0; i < V; i++) visited[i] = 0;
    int count = 0;
    for (int i = 0; i < V; i++) {
        if (!visited[i]) {
            count++;
            dfs(adj, adjColSize, visited, i, V);
        }
    }
    return count;
}

void dfs(int** adj, int* adjColSize, int* visited, int node, int V) {
    visited[node] = 1;
    for (int i = 0; i < V; i++) {
        if (adj[node][i] == 1 && !visited[i]) {
            dfs(adj, adjColSize, visited, i, V);
        }
    }
}

