        for (let neighbor of adjList[node]) {
            if (!visited[neighbor]) {
                this.dfs(neighbor, adjList, visited);
            }
        }
    }

    // Function to count provinces
    numProvinces(adj, V) {
        // Create adjacency list
        let adjList = Array.from({ length: V }, () => []);

        // Convert matrix to list
        for (let i = 0; i < V; i++) {
            for (let j = 0; j < V; j++) {
                if (adj[i][j] === 1 && i !== j) {
                    adjList[i].push(j);
                    adjList[j].push(i);
                }
